"use client";

import { useState } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { motion } from "framer-motion";
import { useAuthStore } from "@/stores/auth-store";

export default function LoginPage() {
  const [email, setEmail] = useState("admin@audira.ai");
  const [password, setPassword] = useState("audira2024");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const router = useRouter();
  const setAuth = useAuthStore((state) => state.setAuth);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError("");

    try {
      const res = await fetch("http://localhost:3378/api/v1/auth/login", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ email, password }),
      });

      const data = await res.json();

      if (data.success) {
        // Use Zustand store to save tokens (single source of truth)
        // This automatically persists to localStorage via persist middleware
        setAuth({
          user: data.data.user,
          tenant: data.data.tenant,
          accessToken: data.data.accessToken,
          refreshToken: data.data.refreshToken,
        });
        
        // Redirect to dashboard
        // AuthGuard will wait for hydration before rendering
        router.push("/dashboard");
      } else {
        setError(data.error || "Login failed");
        setLoading(false);
      }
    } catch (err) {
      // Fallback: demo login tanpa backend
      if (email === "admin@audira.ai" && password === "audira2024") {
        setAuth({
          user: { id: "demo", name: "Audira Team", email: "admin@audira.ai", role: "ADMIN" },
          tenant: { id: "demo-tenant", name: "Audira Demo", slug: "audira-demo" },
          accessToken: "demo-token-" + Date.now(),
          refreshToken: "demo-refresh-" + Date.now(),
        });
        router.push("/dashboard");
      } else {
        setError("Invalid credentials. Use demo account.");
        setLoading(false);
      }
    }
  };

  // ... rest of component remains the same
}
```

**Key Changes:**
- ✅ Import `useAuthStore` from Zustand
- ✅ Call `setAuth()` instead of manual localStorage.setItem
- ✅ Remove dual storage (audira-session)
- ✅ Add error state for better UX
- ✅ Zustand persist middleware handles localStorage automatically

**Why This Works:**
- Single source of truth: Zustand store
- Automatic persistence: persist middleware writes to localStorage
- Correct format: Zustand handles the `{ state: {...}, version: 0 }` format
- No race condition: Store is ready when needed

---

### Task 1.2: Fix API Client Token Retrieval

**File:** `/apps/web/src/lib/api.ts`

**Current Code (BROKEN):**
```typescript
