interface AuthState {
  user: AuthUser | null;
  tenant: Tenant | null;
  accessToken: string | null;
  refreshToken: string | null;
  isAuthenticated: boolean;

  setAuth: (data: {
    user: AuthUser;
    tenant: Tenant;
    accessToken: string;
    refreshToken: string;
  }) => void;
  logout: () => void;
  secureLogout: () => Promise<void>;
  updateUser: (user: Partial<AuthUser>) => void;
  refreshTokens: () => Promise<boolean>;
}

export const useAuthStore = create<AuthState>()(
  persist(
    (set, get) => ({
      user: null,
      tenant: null,
      accessToken: null,
      refreshToken: null,
      isAuthenticated: false,

      setAuth: (data) =>
        set({
          user: data.user,
          tenant: data.tenant,
          accessToken: data.accessToken,
          refreshToken: data.refreshToken,
          isAuthenticated: true,
        }),

      logout: () =>
        set({
          user: null,
          tenant: null,
          accessToken: null,
          refreshToken: null,
          isAuthenticated: false,
        }),

      /**
       * Secure logout: clears offline cache, stored credentials, localStorage,
       * zustand stores, and redirects to login. Completes within 2 seconds.
       */
      secureLogout: async () => {
        const timeoutPromise = new Promise<void>((resolve) =>
          setTimeout(resolve, 2000)
        );

        const cleanupPromise = (async () => {
          // Run all cleanup operations in parallel for speed
          await Promise.allSettled([
            // Clear offline cache via Tauri command
            tauriInvoke("clear_offline_cache"),
            // Delete stored credentials via Tauri command
            tauriInvoke("delete_credential", { account: "access_token" }),
            tauriInvoke("delete_credential", { account: "refresh_token" }),
          ]);

          // Clear all localStorage
          if (typeof window !== "undefined") {
            localStorage.clear();
          }

          // Clear zustand auth state
          set({
            user: null,
            tenant: null,
            accessToken: null,
            refreshToken: null,
            isAuthenticated: false,
          });
        })();

        // Ensure we complete within 2 seconds regardless
        await Promise.race([cleanupPromise, timeoutPromise]);

        // Redirect to login
        if (typeof window !== "undefined") {
          window.location.href = "/login";
        }
      },

      updateUser: (updates) =>
        set((state) => ({
          user: state.user ? { ...state.user, ...updates } : null,
        })),

      /**
       * Refresh access token using refresh token
       * Returns true if successful, false if failed
       */
      refreshTokens: async () => {
        try {
          const refreshToken = get().refreshToken;
          if (!refreshToken) return false;

          const apiUrl = process.env.NEXT_PUBLIC_API_URL || "http://localhost:3378/api/v1";
          const response = await fetch(`${apiUrl}/auth/refresh`, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ refreshToken }),
          });

          if (!response.ok) return false;

          const data = await response.json();
          if (data.success && data.data) {
            set({
              accessToken: data.data.accessToken,
              refreshToken: data.data.refreshToken,
            });
            return true;
          }

          return false;
        } catch (error) {
          console.error("Token refresh failed:", error);
          return false;
        }
      },
    }),
    {
      name: "audira-auth",
      partialize: (state) => ({
        user: state.user,
        tenant: state.tenant,
        accessToken: state.accessToken,
        refreshToken: state.refreshToken,
        isAuthenticated: state.isAuthenticated,
      }),
    }
  )
);

